in="news.xml"; out="$(date +%H%M%S).html"; echo|ansifilter -H|head -n4|tee $out; tail -n15 $in|sed -e "s/<\//\n&/g" -e "s/<\w./\n\n&/g" -e "s/&lt;/</g" -e "s/&gt;/>/g" -e "s/&amp;/\ /g" -e "s/nbsp;/\n/g" | sed -E "s/^<*\W(link|guid|source|font).*//g"|sed -e "s/description>/pre>/g" -e "s/title>/h1>/g" -e "s/pubDate>/code>/g" -e "s/item>/article>/g" -e "s/channel>/main>/g" -e "s/rss>/body>/g" -e "/<image/,/image>/d"|sed -E "/(language|webMaster|copyright)>/d"|sed -e "s/<rss\ .*/<body>/g" -e "s/<?xml.*/<\/head>/" -e "/generator>/d"|tr -s "\n" "\n"|bat --strip-ansi always -pp --line-range 1: |tee -a $out|bat -p
